const items = $input.all();

return items.map((item) => {
  const payload = JSON.parse(JSON.stringify(item.json || {}));
  const cleanPayload = JSON.parse(JSON.stringify(payload));
  delete cleanPayload._runtime;

  return {
    json: {
      document_id: cleanPayload.processing_metadata?.document_id ?? null,
      source_filename: cleanPayload.processing_metadata?.source_filename ?? null,
      ingestion_channel: cleanPayload.processing_metadata?.ingestion_channel ?? null,
      status: cleanPayload.processing_metadata?.status ?? null,
      received_date: cleanPayload.received_date ?? null,
      processed_at: cleanPayload.processing_metadata?.processed_at ?? null,
      payload_jsonb: cleanPayload,
      validation_errors_jsonb: Array.isArray(cleanPayload.processing_metadata?.validation_errors)
        ? cleanPayload.processing_metadata.validation_errors
        : [],
    },
  };
});

const items = $input.all();
const dbResult = items[0]?.json || {};

// Get the original payload passed into this sub-workflow
let originalPayload = {};
try {
  originalPayload = JSON.parse(JSON.stringify(($('Receive Structured Payload').first()?.json) || {}));
} catch (e) {
  // Fallback: reconstruct from DB result if cross-node reference fails
  originalPayload = dbResult.payload_jsonb || dbResult || {};
}

const runtime = originalPayload._runtime && typeof originalPayload._runtime === 'object' ? originalPayload._runtime : {};

originalPayload._runtime = {
  ...runtime,
  persistence_attempted: true,
  persistence_error: dbResult.error?.message || dbResult.error || null,
};

return [{ json: originalPayload }];
